import { useState } from "react";
import Navbar from "../components/Navbar";

export default function CustomerDashboard() {

  const [searched, setSearched] = useState(false);

  const workers = []; // backend will replace later

  const searchWorkers = () => {
    setSearched(true);
  };

  return (

    <div>

      <Navbar />

      <div style={styles.page}>

        <div style={styles.wrapper}>

          {/* HEADER */}
          <div style={styles.header}>

            <h1 style={styles.title}>Find Skilled Workers</h1>
            <p style={styles.subtitle}>
              Search trusted workers near your location
            </p>

          </div>

          {/* SEARCH BOX */}
          <div style={styles.searchCard}>

            <input style={styles.input} placeholder="What work do you need? (plumber, electrician)" />
            <input style={styles.input} placeholder="Location" />
            <input style={styles.input} type="date" />

            <button style={styles.button} onClick={searchWorkers}>
              Search Workers
            </button>

          </div>

          {/* EMPTY STATE */}
          {!searched && (
            <div style={styles.empty}>
              <h3>Start by searching workers</h3>
              <p>No data to show yet</p>
            </div>
          )}

          {/* RESULTS */}
          {searched && (

            <div style={styles.grid}>

              {workers.length === 0 ? (

                <div style={styles.emptyCard}>
                  No workers found
                </div>

              ) : (

                workers.map((w, i) => (

                  <div key={i} style={styles.card}>

                    <h3 style={styles.name}>{w.name}</h3>
                    <p style={styles.text}>{w.skills}</p>
                    <p style={styles.text}>📍 {w.city}</p>

                    <button style={styles.smallBtn}>
                      Send Request
                    </button>

                    <div style={styles.statusBox}>
                      <p>Status: Pending</p>
                      <p>Price: ₹--</p>
                      <p>Decision: Waiting</p>
                    </div>

                  </div>

                ))

              )}

            </div>

          )}

        </div>

      </div>

    </div>
  );
}

// =========================
// MODERN UI STYLES
// =========================
const styles = {

  page: {
    background: "#f4f6f9",
    minHeight: "100vh",
    padding: "30px 10px"
  },

  wrapper: {
    maxWidth: 900,
    margin: "auto"
  },

  header: {
    textAlign: "center",
    marginBottom: 25
  },

  title: {
    margin: 0,
    fontSize: 26,
    fontWeight: 600
  },

  subtitle: {
    margin: 5,
    color: "#666"
  },

  searchCard: {
    background: "white",
    padding: 20,
    borderRadius: 16,
    boxShadow: "0 8px 25px rgba(0,0,0,0.06)",
    display: "grid",
    gap: 10
  },

  input: {
    padding: 12,
    borderRadius: 10,
    border: "1px solid #ddd",
    outline: "none"
  },

  button: {
    padding: 12,
    background: "#2563eb",
    color: "white",
    border: "none",
    borderRadius: 10,
    cursor: "pointer",
    fontWeight: 500
  },

  empty: {
    textAlign: "center",
    marginTop: 60,
    color: "#777"
  },

  grid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit, minmax(260px, 1fr))",
    gap: 16,
    marginTop: 20
  },

  card: {
    background: "white",
    padding: 16,
    borderRadius: 16,
    boxShadow: "0 8px 25px rgba(0,0,0,0.06)"
  },

  name: {
    margin: 0
  },

  text: {
    margin: "5px 0",
    color: "#555"
  },

  smallBtn: {
    marginTop: 10,
    padding: "8px 12px",
    background: "#111",
    color: "white",
    border: "none",
    borderRadius: 8,
    cursor: "pointer"
  },

  statusBox: {
    marginTop: 10,
    fontSize: 13,
    color: "#444"
  },

  emptyCard: {
    background: "white",
    padding: 20,
    borderRadius: 12,
    textAlign: "center"
  }

};
